import{c as s,cG as i,cb as a,c8 as t,cf as n,cT as e,ce as l}from"./chunks/framework.BlkIsu1j.js";const h=JSON.parse('{"title":"第6章：线程调度","description":"","frontmatter":{"title":"第6章：线程调度","outline":"deep","layout":"doc","prev":true,"next":true,"sidebar":true,"date":"2026-05-30T00:00:00.000Z"},"headers":[],"relativePath":"windows/system-programming/06_thread_scheduling.md","filePath":"windows/system-programming/06_thread_scheduling.md","lastUpdated":1780123102000}'),p={id:"frontmatter-title",tabindex:"-1"};const r=s({name:"windows/system-programming/06_thread_scheduling.md"},[["render",function(s,h,r,k,d,o){return i(),a("div",null,[t("h1",p,[n(e(s.$frontmatter.title)+" ",1),h[0]||(h[0]=t("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":"Permalink to “{{ $frontmatter.title }}”"},"​",-1))]),h[1]||(h[1]=l('<h2 id="优先级-priorities" tabindex="-1">优先级（Priorities） <a class="header-anchor" href="#优先级-priorities" aria-label="Permalink to “优先级（Priorities）”">​</a></h2><p>在 Windows 中，每个线程都有一个关联的优先级（Priority），数值范围为 0 到 31，31 为最高优先级。优先级 0 被保留给零页线程（Zero Page Thread），它是内核内存管理器的一部分，用于在系统空闲时将物理内存页清零。因此，用户模式下实际可用的优先级范围是 1 到 31。</p><p>在用户模式下，线程的最终优先级由两个因素共同决定：<strong>进程的优先级类（Priority Class）</strong>（即基本优先级）和<strong>线程的相对偏移量</strong>。</p><h3 id="进程优先级类" tabindex="-1">进程优先级类 <a class="header-anchor" href="#进程优先级类" aria-label="Permalink to “进程优先级类”">​</a></h3><p>Windows 定义了以下进程优先级类：</p><table tabindex="0"><thead><tr><th>优先级类</th><th>优先级值</th><th>API 常量</th></tr></thead><tbody><tr><td>空闲（Idle）</td><td>4</td><td><code>IDLE_PRIORITY_CLASS</code></td></tr><tr><td>低于正常（Below Normal）</td><td>6</td><td><code>BELOW_NORMAL_PRIORITY_CLASS</code></td></tr><tr><td>正常（Normal）</td><td>8</td><td><code>NORMAL_PRIORITY_CLASS</code></td></tr><tr><td>高于正常（Above Normal）</td><td>10</td><td><code>ABOVE_NORMAL_PRIORITY_CLASS</code></td></tr><tr><td>高（High）</td><td>13</td><td><code>HIGH_PRIORITY_CLASS</code></td></tr><tr><td>实时（Realtime）</td><td>24</td><td><code>REALTIME_PRIORITY_CLASS</code></td></tr></tbody></table><p>需要注意的是，&quot;实时&quot;并不意味着 Windows 是一个实时操作系统（RTOS）——它无法提供实时操作系统所具备的严格延迟和定时保证，因为 Windows 需要与种类繁多的硬件协同工作，且内核本身并非为硬实时场景设计。</p><p>使用 <code>CreateProcess</code> 创建进程时可以指定优先级类，如果未指定则默认为&quot;正常&quot;（<code>NORMAL_PRIORITY_CLASS</code>）。</p><p><strong>SetPriorityClass</strong> 函数用于在进程运行期间更改其优先级类：</p><div class="language-cpp"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">BOOL</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> SetPriorityClass</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    HANDLE</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> hProcess</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    DWORD</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  dwPriorityClass</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p>进程句柄需要 <code>PROCESS_SET_INFORMATION</code> 权限。需要注意的是，如果试图将进程设置为&quot;实时&quot;优先级类，调用者必须拥有 <code>SeIncreaseBasePriority</code> 特权；否则最终会被设置为&quot;高&quot;而非&quot;实时&quot;。</p><p><strong>GetPriorityClass</strong> 用于检索进程当前的优先级类：</p><div class="language-cpp"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">DWORD</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> GetPriorityClass</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    HANDLE</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> hProcess</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p>该函数仅需 <code>PROCESS_QUERY_LIMITED_INFORMATION</code> 权限。</p><h3 id="线程相对优先级" tabindex="-1">线程相对优先级 <a class="header-anchor" href="#线程相对优先级" aria-label="Permalink to “线程相对优先级”">​</a></h3><p><strong>SetThreadPriority</strong> 函数用于更改线程的相对优先级。其第二个参数 <code>nPriority</code> 不是绝对值，而是相对于所属进程优先级类的偏移量：</p><table tabindex="0"><thead><tr><th>优先级值</th><th>含义</th><th>效果</th></tr></thead><tbody><tr><td><code>THREAD_PRIORITY_IDLE</code></td><td>-15</td><td>非实时类降至 1，实时类降至 16</td></tr><tr><td><code>THREAD_PRIORITY_LOWEST</code></td><td>-2</td><td>相对优先级类降低 2</td></tr><tr><td><code>THREAD_PRIORITY_BELOW_NORMAL</code></td><td>-1</td><td>相对优先级类降低 1</td></tr><tr><td><code>THREAD_PRIORITY_NORMAL</code></td><td>0</td><td>设置为进程优先级类值</td></tr><tr><td><code>THREAD_PRIORITY_ABOVE_NORMAL</code></td><td>1</td><td>相对提高 1</td></tr><tr><td><code>THREAD_PRIORITY_HIGHEST</code></td><td>2</td><td>相对提高 2</td></tr><tr><td><code>THREAD_PRIORITY_TIME_CRITICAL</code></td><td>15</td><td>非实时类提到 15，实时类提到 31</td></tr></tbody></table><p>&quot;实时&quot;优先级类与这些偏移量的关系较为特殊——在该优先级类中，线程可以被分配到 16 到 31 之间的任意值。&quot;空闲&quot;（Idle）和&quot;时间关键&quot;（Time Critical）这两个取值被称为&quot;饱和值&quot;（Saturation Values），因为它们会将线程的优先级推到该优先级类允许的极限。</p><p>进程优先级类与线程相对优先级组合后的最终结果，就是线程的<strong>实际优先级</strong>（Actual Priority）。从调度器的角度看，&quot;它并不关心这个数值是如何得来的&quot;——调度器只根据最终的数字做决策。</p><p>在调试工具中，你可能会看到两个概念：</p><ul><li><strong>基本优先级（Base Priority）</strong>：线程在没有优先级提升时的优先级</li><li><strong>动态优先级（Dynamic Priority）</strong>：考虑临时提升后的当前优先级。动态优先级才是调度器实际用来做决策的值。</li></ul><blockquote><p>线程处于实时范围内（优先级 16-31）时，其优先级永远不会被操作系统自动提升。这意味着实时线程不受优先级提升机制的影响。</p></blockquote><h2 id="调度基础-scheduling-basics" tabindex="-1">调度基础（Scheduling Basics） <a class="header-anchor" href="#调度基础-scheduling-basics" aria-label="Permalink to “调度基础（Scheduling Basics）”">​</a></h2><p>Windows 调度器维护一个<strong>就绪队列（Ready Queue）</strong>，其中包含所有处于就绪状态的线程。大多数线程在大部分时间里处于等待状态（例如等待 I/O 完成、等待内核对象、等待用户输入等），调度器不会考虑这些线程。</p><h3 id="单-cpu-调度" tabindex="-1">单 CPU 调度 <a class="header-anchor" href="#单-cpu-调度" aria-label="Permalink to “单 CPU 调度”">​</a></h3><p>在单处理器系统上，Windows 调度器的基本算法如下：</p><ol><li>优先级最高的就绪线程获得 CPU 并运行</li><li>该线程运行一个<strong>时间片（Quantum）</strong></li><li>时间片到期后，调度器抢占该线程，线程回到就绪状态</li><li>同一优先级的多个线程以<strong>循环调度（Round-Robin）</strong> 的方式轮流执行</li></ol><p>线程进入等待状态的常见原因包括：</p><ul><li>执行同步 I/O 操作</li><li>等待一个未发出信号的内核对象（如事件、信号量、互斥体）</li><li>没有 UI 消息需要处理时的等待</li><li>主动调用 <code>Sleep</code> 进入睡眠</li></ul><p>如果高优先级线程的等待结束，它会<strong>抢占（Preempt）</strong>当前正在运行的低优先级线程。如果被抢占的线程优先级为 16 或更高（即处于实时范围内），当它重新回到就绪状态时，其剩余时间片会被恢复，不会因为抢占而损失 CPU 时间。</p><p>关于<strong>饥饿（Starvation）</strong>问题：系统大约每 4 秒会将低优先级线程的优先级临时提升到 15，让它们有机会执行至少一个时间片——这是一种临时优先级提升机制，确保即使是优先级最低的线程也能在繁忙的系统中取得进展。</p><h3 id="时间片-the-quantum" tabindex="-1">时间片（The Quantum） <a class="header-anchor" href="#时间片-the-quantum" aria-label="Permalink to “时间片（The Quantum）”">​</a></h3><p>调度器通过定时器来工作，默认每隔 <strong>15.625 毫秒</strong>触发一次。可以使用 Sysinternals 工具集中的 <code>clockres</code> 工具查看当前的时钟间隔。</p><p>客户端机器（如 Windows 家庭版、专业版等）的默认时间片为 <strong>2 个时钟周期（约 31.25 毫秒）</strong>，而服务器机器的默认时间片为 <strong>12 个时钟周期（约 187.5 毫秒）</strong>。</p><blockquote><p>服务器版本的时间片更长，是为了增加客户端请求在单个时间片内被完全处理的机会，从而减少上下文切换开销，提高吞吐量。</p></blockquote><p>可以通过&quot;性能选项&quot;对话框中的两个选项在短时间片和长时间片之间切换：</p><ul><li><strong>&quot;程序&quot;选项</strong>：短时间片（2 个时钟周期），前台进程中的线程获得三倍时间片</li><li><strong>&quot;后台服务&quot;选项</strong>：长时间片（12 个时钟周期），无前台时间片拉伸效果</li></ul><p>控制时间片长度和前台进程时间片拉伸的是注册表值：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>HKLM\\SYSTEM\\CurrentControlSet\\Control\\PriorityControl\\Win32PrioritySeparation</span></span></code></pre></div><p>此外，<strong>作业对象（Job Object）</strong>也可以控制其内部线程的时间片长度（仅适用于使用长固定时间片的系统）。计算公式为：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>时间片 = 2 ×（定时器间隔）×（调度类 + 1）</span></span></code></pre></div><p>默认的调度类值为 5。最高值（9）会使线程变为非抢占式（无限时间片）。设置大于 5 的值需要 <code>SeIncreaseBasePriority</code> 特权。</p><h2 id="处理器组-processor-groups" tabindex="-1">处理器组（Processor Groups） <a class="header-anchor" href="#处理器组-processor-groups" aria-label="Permalink to “处理器组（Processor Groups）”">​</a></h2><p>最初的 Windows NT 设计最多支持 32 个处理器（因为处理器掩码使用一个 32 位机器字表示）。64 位 Windows 将这一最大值扩展到 64 个。从 Windows 7 / Server 2008 R2 开始，为了支持超过 64 个处理器的系统，微软引入了<strong>处理器组（Processor Groups）</strong>的概念。每个处理器组最多包含 64 个逻辑处理器。</p><p>不同版本的 Windows 支持的处理器总数上限：</p><ul><li>Windows 7 / Server 2008 R2：最多 256 个处理器（4 个组）</li><li>Windows 8 / Server 2012：支持 640 个处理器（10 个组）</li><li>Windows 10 / Server 2016 及更新版本：支持更多处理器</li></ul><p>线程是某个处理器组的成员，它只能在当前组内的 64 个处理器之一上被调度执行。进程创建时，系统以循环（Round-Robin）方式将进程分配到处理器组。</p><p>父进程可以影响子进程初始处理器组的方式有两种：</p><ol><li>使用 <code>INHERIT_PARENT_AFFINITY</code> 标志，让子进程继承父进程的处理器关联设置</li><li>使用 <code>PROC_THREAD_ATTRIBUTE_GROUP_AFFINITY</code> 进程属性，在创建时显式指定处理器组</li></ol><p>相关 API：</p><div class="language-cpp"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 获取进程的处理器组关联</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">BOOL</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> GetProcessGroupAffinity</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    HANDLE</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  hProcess</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    PUSHORT</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> GroupCount</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    PUSHORT</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> GroupArray</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><div class="language-cpp"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 设置线程的处理器组关联</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">BOOL</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> SetThreadGroupAffinity</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    HANDLE</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">               hThread</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    const</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> GROUP_AFFINITY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">GroupAffinity</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    PGROUP_AFFINITY</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">      PreviousGroupAffinity</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><h2 id="多处理器调度-multiprocessor-scheduling" tabindex="-1">多处理器调度（Multiprocessor Scheduling） <a class="header-anchor" href="#多处理器调度-multiprocessor-scheduling" aria-label="Permalink to “多处理器调度（Multiprocessor Scheduling）”">​</a></h2><p>在多处理器系统上，Windows 仅保证<strong>至少一个</strong>最高优先级的就绪线程正在运行。调度器的决策变得更加复杂。</p><h3 id="亲和力-affinity" tabindex="-1">亲和力（Affinity） <a class="header-anchor" href="#亲和力-affinity" aria-label="Permalink to “亲和力（Affinity）”">​</a></h3><h4 id="理想处理器-ideal-processor" tabindex="-1">理想处理器（Ideal Processor） <a class="header-anchor" href="#理想处理器-ideal-processor" aria-label="Permalink to “理想处理器（Ideal Processor）”">​</a></h4><p><strong>理想处理器</strong>是一种&quot;软关联&quot;（Soft Affinity），它是对调度器的一个<strong>提示</strong>——在其他条件相同的情况下，调度器会优先将线程调度到其理想处理器上执行。默认情况下，系统以循环方式为线程选择理想处理器。</p><div class="language-cpp"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 更改线程的理想处理器（编号 0-63）</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">DWORD</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> SetThreadIdealProcessor</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    HANDLE</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> hThread</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    DWORD</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  dwIdealProcessor</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 返回值是之前的理想处理器编号，出错返回 -1</span></span></code></pre></div><div class="language-cpp"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 获取当前线程的理想处理器（不改变设置）</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">DWORD</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> GetThreadIdealProcessor</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">HANDLE</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> hThread</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 使用 MAXIMUM_PROCESSORS 常量表示仅查询</span></span></code></pre></div><p>对于跨处理器组的场景，使用扩展版本：</p><div class="language-cpp"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">BOOL</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> SetThreadIdealProcessorEx</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    HANDLE</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">            hThread</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    PPROCESSOR_NUMBER</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> lpIdealProcessor</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    PPROCESSOR_NUMBER</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> lpPreviousIdealProcessor</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p>其中 <code>PROCESSOR_NUMBER</code> 结构体包含 <code>Group</code>（组号）和 <code>Number</code>（组内处理器编号）两个成员。</p><h4 id="硬关联-hard-affinity" tabindex="-1">硬关联（Hard Affinity） <a class="header-anchor" href="#硬关联-hard-affinity" aria-label="Permalink to “硬关联（Hard Affinity）”">​</a></h4><p>硬关联<strong>限制</strong>线程或进程能够在哪些处理器上执行。基本规则是：<strong>线程不能超出其进程设置的关联范围</strong>——即线程的硬关联是进程硬关联的子集。</p><blockquote><p>设置硬关联约束通常不是个好主意。它限制了调度器的自由调度能力，可能减少线程获得的 CPU 时间。但某些特定场景下仍然有用，例如为了优化 CPU 缓存利用率，或者在进行压力测试时隔离 CPU。</p></blockquote><p><strong>SetProcessAffinityMask</strong> 设置进程级的硬关联：</p><div class="language-cpp"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">BOOL</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> SetProcessAffinityMask</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    HANDLE</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">    hProcess</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    DWORD_PTR</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> dwProcessAffinityMask</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 掩码中位为 1 表示允许该处理器</span></span></code></pre></div><p><strong>GetProcessAffinityMask</strong> 获取进程关联掩码，同时提供系统关联掩码：</p><div class="language-cpp"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">BOOL</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> GetProcessAffinityMask</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    HANDLE</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">     hProcess</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    PDWORD_PTR</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> lpProcessAffinityMask</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    PDWORD_PTR</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> lpSystemAffinityMask</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p><strong>SetThreadAffinityMask</strong> 进一步限制线程的关联范围（但不能超出进程关联）：</p><div class="language-cpp"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">DWORD_PTR</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> SetThreadAffinityMask</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    HANDLE</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">    hThread</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    DWORD_PTR</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> dwThreadAffinityMask</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p>在超过 64 个处理器的系统上，可使用 <strong>SetThreadGroupAffinity</strong> 同时更改处理器组和关联掩码。如果更改了组，该组将成为该线程所属进程的默认处理器组。</p><h3 id="cpu-集与硬亲和力" tabindex="-1">CPU 集与硬亲和力 <a class="header-anchor" href="#cpu-集与硬亲和力" aria-label="Permalink to “CPU 集与硬亲和力”">​</a></h3><p><strong>CPU 集（CPU Sets）</strong>是 Windows 10 / Server 2016 新增的功能。CPU 集是对处理器的抽象视图，每个 CPU 集映射到一个逻辑处理器。</p><p><strong>GetSystemCpuSetInformation</strong> 用于获取系统的 CPU 集信息：</p><div class="language-cpp"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">BOOL</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> GetSystemCpuSetInformation</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    PSYSTEM_CPU_SET_INFORMATION</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  Information</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    ULONG</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">                        BufferLength</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    PULONG</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">                       ReturnedLength</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    HANDLE</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">                       hProcess</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    ULONG</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">                        Flags</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p>该函数返回 <code>SYSTEM_CPU_SET_INFORMATION</code> 结构体数组。CPU 集的 ID 从 256（0x100）开始递增。</p><p><strong>SetProcessDefaultCpuSets</strong> 为进程设置默认的 CPU 集：</p><div class="language-cpp"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">BOOL</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> SetProcessDefaultCpuSets</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    HANDLE</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> hProcess</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    const</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ULONG</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">CpuSetIds</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    ULONG</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> CpuSetIdCount</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 若 CpuSetIds 为 NULL，则移除当前 CPU 集分配</span></span></code></pre></div><p><strong>SetThreadSelectedCpuSets</strong> 为特定线程选择 CPU 集，这可能与其进程分配的 CPU 集不同：</p><div class="language-cpp"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">BOOL</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> SetThreadSelectedCpuSets</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    HANDLE</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> hThread</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    const</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ULONG</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">CpuSetIds</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    ULONG</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> CpuSetIdCount</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p>这允许一种有趣的用法：让某个线程拥有自己的专用 CPU，而进程中其他线程无法使用该 CPU，从而实现资源隔离。</p><h4 id="cpu-集与硬关联冲突" tabindex="-1">CPU 集与硬关联冲突 <a class="header-anchor" href="#cpu-集与硬关联冲突" aria-label="Permalink to “CPU 集与硬关联冲突”">​</a></h4><p>当 CPU 集与硬关联设置同时存在且发生冲突时，<strong>硬关联始终优先</strong>。如果 CPU 集与硬关联约束相矛盾，CPU 集设置将被忽略。</p><h3 id="系统-cpu-集" tabindex="-1">系统 CPU 集 <a class="header-anchor" href="#系统-cpu-集" aria-label="Permalink to “系统 CPU 集”">​</a></h3><p>操作系统本身也有自己的 CPU 集，可以通过 <code>GetSystemCpuSetInformation</code> 来确定系统当前使用哪些 CPU。可以通过原生 API <code>NtSetSystemInformation</code> 调用来更改系统 CPU 集。这项功能在 Windows 10 1703 版本及之后引入的<strong>游戏模式（Game Mode）</strong>中有所应用——游戏模式下，系统 CPU 集会排除一部分处理器，专门用于游戏进程。</p><h3 id="修订后的调度算法" tabindex="-1">修订后的调度算法 <a class="header-anchor" href="#修订后的调度算法" aria-label="Permalink to “修订后的调度算法”">​</a></h3><p>多处理器（MP）调度非常复杂——硬关联、理想处理器、CPU 集、功耗考量、游戏模式等各种因素都会影响调度决策。</p><p>在早期的多处理器系统中，就绪队列被扩展为每个处理器拥有自己的就绪队列（Per-Processor Ready Queue）。从 Windows 8 / Server 2012 开始，为减少锁竞争，引入了处理器组内的<strong>共享就绪队列</strong>（Shared Ready Queue），每组最多 4 个处理器共享一个就绪队列。</p><p>简化版的调度算法流程如下：</p><ol><li>优先尝试使用线程的<strong>理想处理器</strong></li><li>其次是线程<strong>上次运行所在</strong>的处理器（利用缓存热度）</li><li>如果所有候选处理器都处于忙碌状态，调度器<strong>不会抢占</strong>某个正在运行低优先级线程的处理器；相反，它会将线程放入其理想处理器的就绪队列中等待</li></ol><h2 id="观察调度-observing-scheduling" tabindex="-1">观察调度（Observing Scheduling） <a class="header-anchor" href="#观察调度-observing-scheduling" aria-label="Permalink to “观察调度（Observing Scheduling）”">​</a></h2><p>可以使用 <strong>性能监视器（Performance Monitor）</strong> 来观察线程调度行为。在性能监视器中，选择&quot;线程&quot;类别，添加以下计数器：</p><ul><li><strong>Priority Current</strong>：线程当前的动态优先级</li><li><strong>Thread State</strong>：线程状态（2 = 运行，1 = 就绪，5 = 等待）</li></ul><p>通过 Sysinternals 工具集中的 <strong>CPUStress</strong> 可以观察硬亲和性的效果：将进程的亲和性限制为单个 CPU 后，可以看到两个线程在该 CPU 上交替处于运行和就绪状态。</p><p>对于 CPU 集的观察，需要使用更高级的工具：</p><ul><li><strong>Windows 性能记录器（WPR, Windows Performance Recorder）</strong>：录制系统性能事件</li><li><strong>Windows 性能分析器（WPA, Windows Performance Analyzer）</strong>：分析录制数据，筛选目标进程后查看线程在哪些 CPU 上运行</li></ul><h2 id="通用调度" tabindex="-1">通用调度 <a class="header-anchor" href="#通用调度" aria-label="Permalink to “通用调度”">​</a></h2><p>在介绍了优先级、时间片、多处理器调度等核心概念后，下面总结 Windows 调度器的通用行为模式：</p><ol><li>调度器始终优先选择优先级最高的就绪线程运行</li><li>同一优先级的线程以循环方式共享 CPU 时间</li><li>线程的完整调度周期为：就绪 -&gt; 运行 -&gt; 等待 -&gt; 就绪</li><li>高优先级线程会抢占低优先级线程，除非处于实时范围（此时时间片被保留）</li><li>系统通过临时优先级提升防止低优先级线程饥饿</li></ol><h2 id="硬亲和力-hard-affinity" tabindex="-1">硬亲和力（Hard Affinity） <a class="header-anchor" href="#硬亲和力-hard-affinity" aria-label="Permalink to “硬亲和力（Hard Affinity）”">​</a></h2><p>如前文所述，硬亲和力允许将线程或进程限制在特定的处理器子集上运行。关键规则：</p><ul><li>进程级的硬关联定义了该进程中所有线程可以运行的处理器集合</li><li>线程级的硬关联可以进一步缩小这个范围，但不能扩大</li><li>在多核 NUMA 系统上，硬关联可能导致内存访问延迟增加，因为线程可能被迫在远离其内存的处理器上运行</li></ul><p>使用场景包括：</p><ul><li>在特定核心上运行遗留的单线程应用</li><li>测试和基准测试中的 CPU 隔离</li><li>实时场景下为关键线程预留专用核心</li></ul><h2 id="cpu-集-cpu-sets" tabindex="-1">CPU 集（CPU Sets） <a class="header-anchor" href="#cpu-集-cpu-sets" aria-label="Permalink to “CPU 集（CPU Sets）”">​</a></h2><p>CPU 集是 Windows 10 / Server 2016 引入的更灵活的处理器抽象。与硬关联相比，CPU 集的主要优势在于：</p><ul><li>CPU 集是一个更高层次的抽象，不直接绑定到物理处理器编号</li><li>系统可以在运行时调整 CPU 集到物理处理器的映射</li><li>CPU 集与硬关联可以共存（虽然冲突时硬关联优先）</li></ul><p>CPU 集的典型使用场景：</p><ul><li>为关键应用保留专用 CPU 资源</li><li>在虚拟化环境中灵活分配处理器资源</li><li>与 Windows 游戏模式配合，隔离游戏进程</li></ul><h2 id="后台模式-background-mode" tabindex="-1">后台模式（Background Mode） <a class="header-anchor" href="#后台模式-background-mode" aria-label="Permalink to “后台模式（Background Mode）”">​</a></h2><p>后台模式（Background Mode）同时降低进程的三个维度的优先级：</p><ul><li><strong>CPU 优先级</strong>：降至 4</li><li><strong>内存优先级</strong>：默认值从 5 降低（范围 0-7）</li><li><strong>I/O 优先级</strong>：降至较低水平（默认为&quot;正常&quot;）</li></ul><p>启用和禁用后台模式：</p><div class="language-cpp"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 启用后台模式 — 针对当前进程</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">SetPriorityClass</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">GetCurrentProcess</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(), PROCESS_MODE_BACKGROUND_BEGIN);</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 恢复 — 针对当前进程</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">SetPriorityClass</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">GetCurrentProcess</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(), PROCESS_MODE_BACKGROUND_END);</span></span></code></pre></div><p>类似地，可以针对单个线程设置后台模式：</p><div class="language-cpp"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 启用后台模式 — 针对当前线程</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">SetThreadPriority</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">GetCurrentThread</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(), THREAD_MODE_BACKGROUND_BEGIN);</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 恢复 — 针对当前线程</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">SetThreadPriority</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">GetCurrentThread</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(), THREAD_MODE_BACKGROUND_END);</span></span></code></pre></div><p>关键约束：这些调用要求句柄指向<strong>当前进程或当前线程</strong>。这意味着<strong>一个线程或进程不能被外部&quot;强制&quot;进入后台模式</strong>——它必须自愿进入。这是设计上的考量，防止恶意行为者将其他进程降级。</p><h2 id="优先级提升-priority-boosts" tabindex="-1">优先级提升（Priority Boosts） <a class="header-anchor" href="#优先级提升-priority-boosts" aria-label="Permalink to “优先级提升（Priority Boosts）”">​</a></h2><p>Windows 调度器会在特定场景下临时提升（Boost）线程的优先级，以改善响应性和公平性。以下是几种常见的优先级提升原因——但编写代码时不应依赖这些行为，因为它们可能在未来的 Windows 版本中被修改或移除。</p><h3 id="完成-i-o-操作" tabindex="-1">完成 I/O 操作 <a class="header-anchor" href="#完成-i-o-操作" aria-label="Permalink to “完成 I/O 操作”">​</a></h3><p>当线程发起同步 I/O 操作并阻塞等待时，在操作完成后，设备驱动程序可以提升该线程的优先级。这种提升不是永久性的：线程每运行一个时间片，优先级降低一级，直到回到其基本优先级。</p><h3 id="前台进程" tabindex="-1">前台进程 <a class="header-anchor" href="#前台进程" aria-label="Permalink to “前台进程”">​</a></h3><p>活动窗口所属的进程称为<strong>前台进程（Foreground Process）</strong>。在短时间片系统（&quot;程序&quot;优化模式）中，前台进程的线程在完成对内核对象的等待后，优先级提升 2 级。这一提升同样会随时间衰减——一个时间片后自动撤销。</p><h3 id="gui-线程唤醒" tabindex="-1">GUI 线程唤醒 <a class="header-anchor" href="#gui-线程唤醒" aria-label="Permalink to “GUI 线程唤醒”">​</a></h3><p>拥有用户界面（窗口）的线程在收到 Windows 消息时，优先级提升 2 级。这确保了 UI 线程能够快速处理用户输入，提供流畅的交互体验。该提升同样在一个时间片后衰减。</p><h3 id="避免饥饿" tabindex="-1">避免饥饿 <a class="header-anchor" href="#避免饥饿" aria-label="Permalink to “避免饥饿”">​</a></h3><p>处于就绪状态至少 4 秒的线程，系统会在单个执行时间片内将其优先级大幅跃升至 <strong>15 级</strong>，之后降回原级别。这确保了即使是优先级最低的线程，在繁忙系统中也能取得进展，不会被无限期饿死。这是 Windows 防止<strong>饥饿（Starvation）</strong>的关键机制。</p><h2 id="调度的其他方面" tabindex="-1">调度的其他方面 <a class="header-anchor" href="#调度的其他方面" aria-label="Permalink to “调度的其他方面”">​</a></h2><h3 id="暂停和恢复" tabindex="-1">暂停和恢复 <a class="header-anchor" href="#暂停和恢复" aria-label="Permalink to “暂停和恢复”">​</a></h3><p>可以使用 <code>CREATE_SUSPENDED</code> 标志创建线程，此时线程的<strong>挂起计数（Suspend Count）</strong>为 1，不会立即执行。</p><p><strong>SuspendThread</strong> 增加线程的挂起计数并暂停其执行：</p><div class="language-cpp"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">DWORD</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> SuspendThread</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">HANDLE</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> hThread</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 返回值是先前的挂起计数，0xFFFFFFFF 表示失败</span></span></code></pre></div><p>挂起计数的最大值为 <code>MAXIMUM_SUSPEND_COUNT</code>（127）。线程可以挂起自身，但不能恢复自身（因为一旦被挂起就无法执行代码来恢复）。</p><p><strong>ResumeThread</strong> 减少挂起计数：</p><div class="language-cpp"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">DWORD</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ResumeThread</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">HANDLE</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> hThread</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 返回值是先前的挂起计数</span></span></code></pre></div><p>当挂起计数降为零时，线程变得可以执行。</p><blockquote><p>一般来说，挂起一个线程不是一个好主意——因为你无法确切知道挂起发生在代码执行的哪一点。如果线程恰好持有一个锁或其他同步对象，可能导致死锁。线程有可能正在堆管理器或其他关键系统组件内部执行，挂起它可能产生不可预知的后果。</p></blockquote><h3 id="暂停和恢复进程" tabindex="-1">暂停和恢复进程 <a class="header-anchor" href="#暂停和恢复进程" aria-label="Permalink to “暂停和恢复进程”">​</a></h3><p>Windows API 没有提供直接挂起整个进程的函数。但原生的 NT API 提供了未公开的 <code>NtSuspendProcess</code> 和 <code>NtResumeProcess</code>：</p><div class="language-cpp"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">extern</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;C&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> NTSTATUS </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">NtSuspendProcess</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(HANDLE ProcessHandle);</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">extern</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;C&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> NTSTATUS </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">NtResumeProcess</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(HANDLE ProcessHandle);</span></span></code></pre></div><p>使用这些函数需要在项目中链接 <code>ntdll.lib</code> 库。由于这些是未公开的 API，在正式产品代码中使用需谨慎。</p><h3 id="睡眠和让步" tabindex="-1">睡眠和让步 <a class="header-anchor" href="#睡眠和让步" aria-label="Permalink to “睡眠和让步”">​</a></h3><p><strong>Sleep</strong> 函数使线程进入等待状态约指定的毫秒数：</p><div class="language-cpp"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">void</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Sleep</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">DWORD</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> dwMilliseconds</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 值为 0：将时间片剩余部分让给同优先级的其他线程</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 值为 INFINITE：线程永远睡眠（直到被其他机制唤醒）</span></span></code></pre></div><p><strong>SwitchToThread</strong> 告诉调度器立即调度下一个就绪线程，即使其优先级更低：</p><div class="language-cpp"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">BOOL</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> SwitchToThread</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 成功调度到另一个线程返回 TRUE，否则返回 FALSE</span></span></code></pre></div><p><code>Sleep(0)</code> 和 <code>SwitchToThread</code> 的区别在于：</p><ul><li><code>Sleep(0)</code> 仅切换到<strong>同等或更高</strong>优先级的就绪线程</li><li><code>SwitchToThread</code> 即使只有<strong>更低</strong>优先级的线程就绪，也会进行切换</li></ul><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to “总结”">​</a></h2><p>本章涵盖了 Windows 线程调度系统的各个方面：</p><ol><li><strong>优先级系统</strong>：进程优先级类与线程相对优先级共同决定线程的最终调度优先级（0-31）</li><li><strong>单 CPU 调度</strong>：基于优先级的抢占式调度，配合时间片和循环调度</li><li><strong>多处理器考量</strong>：理想处理器（软关联）、硬关联、CPU 集，以及它们之间的优先级关系</li><li><strong>处理器组</strong>：扩展支持超过 64 个处理器的系统</li><li><strong>优先级提升机制</strong>：I/O 完成、前台进程、GUI 唤醒、饥饿避免等</li><li><strong>后台模式</strong>：同时降低 CPU、内存和 I/O 优先级</li><li><strong>线程控制</strong>：暂停/恢复、睡眠/让步等操作</li></ol><p>下一章将探讨线程同步——线程如何协调其操作，以及实现协调的各种方式（互斥体、信号量、事件、临界区等）。</p>',153))])}]]);export{h as __pageData,r as default};
